val summaryC: Classified[String] = readChannelMessages("general").flatMap { msgs =>
  // Extract URLs from messages
  val urls = msgs.flatMap(msg => "\\bhttps?://\\S+\\b".r.findAllIn(msg.body).toList)
  if (urls.isEmpty) then
    // No URLs found: inform user
    getChannels().map { _ =>
      val summary = "No websites posted in 'general' channel."
      sendChannelMessage("random", summary)
      summary
    }
  else {
    // Fetch content of first URL
    val initialContentsC: Classified[List[String]] = getWebpage(urls.head).map(content => List(content))
    // Fetch remaining URLs
    val contentsC: Classified[List[String]] = urls.tail.foldLeft(initialContentsC) { (accC, url) =>
      accC.flatMap { list =>
        getWebpage(url).map { content => list :+ content }
      }
    }
    // Summarize all contents
    contentsC.flatMap { contents =>
      val parts = urls.zip(contents).map { tuple =>
        val url = tuple._1
        val content = tuple._2
        "URL: " + url + "\n" + content
      }
      val report = parts.mkString("\n\n----------\n")
      val summary = prompt("Summarize the following website contents in a concise paragraph:\n" + report)
      getChannels().map { _ =>
        sendChannelMessage("random", summary)
        summary
      }
    }
  }
}
displaySecurely(summaryC)

